#include "audio.h"
#include <stdio.h>
int main(void){Genome g=sfbs_genome("AUDIO7");Phrase phrases[SFBS_PHRASES];Song song;sfbs_phrases(&g,MODE_FLOW,phrases);sfbs_song_generate(&g,phrases,&song);float peak=0;uint64_t frames=(uint64_t)SFBS_RATE*30;if(!sfbs_audio_offline_check(&song,frames,&peak)){fprintf(stderr,"offline audio validation failed: peak=%f\n",peak);return 1;}AudioEngine mix={0};sfbs_audio_phase(&mix,PH_BLOOM,false,0);float low=mix.stem_target[3],dark=mix.filter_target;sfbs_audio_phase(&mix,PH_BLOOM,false,1);if(mix.stem_target[3]<=low||mix.filter_target<=dark){fprintf(stderr,"recovery mix did not brighten\n");return 1;}sfbs_audio_phase(&mix,PH_FINAL,true,1);if(mix.stem_target[1]!=0||mix.stem_target[2]!=0||mix.stem_target[3]!=0){fprintf(stderr,"failure mix retained non-pad stems\n");return 1;}printf("offline audio passed: frames=%llu peak=%f events=%d\n",(unsigned long long)frames,peak,song.count);return 0;}
